#include<bits/stdc++.h>
using namespace std;
struct c{int en,ta;}a[200];
bool cmp(c x,c y){return x.en>y.en;}
int main(void){int tmp,n,tmp2,p,ans;
	cin>>tmp;
	n=pow(2,tmp);
	for(int i=1;i<=n;i++){
		cin>>a[i].en;
		a[i].ta=i;
	}
	sort(a+1,a+n/2+1,cmp);
	sort(a+n/2+1,a+n+1,cmp);
	if(a[1].en>a[n/2+1].en){cout<<a[n/2+1].ta;}
	else{cout<<a[1].ta;}
	return false;
}
